                        var expressao = q
                            .replace(/x/gi, '*')       // x → multiplicação
                            .replace(/×/g, '*')        // × → multiplicação
                            .replace(/÷/g, '/')        // ÷ → divisão
                            .replace(/,/g, '.')        // vírgula → ponto decimal
                            .replace(/\s+/g, '')       // remove espaços
                            .replace(/[^0-9+\-*/().%]/g, '') // mantém só caracteres matemáticos

                        // Validação de segurança
                        if (!expressao) return reply('❌ Expressão inválida.')
                        if (/[+\-*/]{2,}/.test(expressao.replace(/[()]/g, ''))) {
                            return reply('❌ Expressão inválida. Operadores duplicados.')
                        }

                        // Calcula de forma segura (sem eval)
                        var resultado = Function('"use strict"; return (' + expressao + ')')()

                        // Verifica se o resultado é um número válido
                        if (typeof resultado !== 'number' || !isFinite(resultado)) {
                            return reply('❌ Resultado inválido (divisão por zero ou erro).')
                        }

                        // Formata o resultado: troca ponto por vírgula para exibição
                        var resultadoFormatado = parseFloat(resultado.toFixed(10)).toString().replace('.', ',')

                        reply(`🧮 *Calculadora*\n\n📝 Expressão: ${q}\n✅ Resultado: *${resultadoFormatado}*`)
