                        bg.composite(moldura, 100, 160)

                        var fonteGrande = await Jimp.loadFont(JimpModule.FONT_SANS_64_WHITE)
                        var fontePequena = await Jimp.loadFont(JimpModule.FONT_SANS_32_WHITE)

