                        var dataBtc = await resBtc.json();
                        var precoBRL = dataBtc.bitcoin.brl.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
                        var precoUSD = dataBtc.bitcoin.usd.toLocaleString('en-US', { style: 'currency', currency: 'USD' });
                        var mensagemBtc = `*Cotacao Atual do Bitcoin (BTC)*\n\nReal (BRL): *${precoBRL}*\nDolar (USD): *${precoUSD}*`;
                        reply(mensagemBtc);
