                        var domain = q.toLowerCase().replace(/^https?:\/\//, '');
                        reply("Consultando DNS...");

                        var res = await fetchJson(`https://api.siputzx.my.id/api/tools/dns?domain=${domain}`);
                        if (!res || !res.status) return reply("Não foi possível consultar o domínio. Verifique se ele está correto.");

                        var records = res.data.records;
                        var a = records.a.response.answer || [];
                        var aaaa = records.aaaa.response.answer || [];
                        var txt = records.txt.response.answer || [];

                        var text = `*Resultados DNS de:* ${domain}\n`;

                        if (a.length > 0) {
                            text += `\n*Registros A:*\n`;
                            for (var r of a) {
                                var ip = r.record.ipv4;
                                var org = r.ipInfo?.org || 'Desconhecida';
                                var country = r.ipInfo?.country || 'Desconhecido';
                                text += `• ${ip} (${org}, ${country})\n`;
                            }
                        }

                        if (aaaa.length > 0) {
                            text += `\n*Registros AAAA:*\n`;
                            for (var r of aaaa) {
                                var ip = r.record.ipv6;
                                var org = r.ipInfo?.org || 'Desconhecida';
                                var country = r.ipInfo?.country || 'Desconhecido';
                                text += `• ${ip} (${org}, ${country})\n`;
                            }
                        }

                        if (txt.length > 0) {
                            text += `\n*Registros TXT:*\n`;
                            for (var r of txt) {
                                text += `• ${r.record.strings.join(' ')}\n`;
                            }
                        }

