// ========= UTIL: dividir texto em partes (evita erro de limite do WhatsApp) =========
function splitText(text = "", maxLen = 3500) {
    var parts = [];
    var current = text;

    while (current.length > maxLen) {
        var cut = current.lastIndexOf("\n", maxLen);
        if (cut < 500) cut = maxLen; // se não achar quebra boa, corta no max mesmo
        parts.push(current.slice(0, cut));
        current = current.slice(cut);
    }
    if (current.trim()) parts.push(current);
    return parts;
}

// ===== dividir texto grande =====
function dividirTexto(texto = "", max = 3500) {
    var partes = [];
    var atual = texto;

    while (atual.length > max) {
        partes.push(atual.slice(0, max));
        atual = atual.slice(max);
    }
    if (atual) partes.push(atual);
    return partes;
}



